const item = $input.first().json;
const response = String(item.response ?? '');
const salvaged = String(item.salvaged ?? '');
const rc = Number(item.rc);

// Rule 1: empty response → UNKNOWN (failed)
if (response.trim() === '') {
  return [{ json: { outcome: 'UNKNOWN', rawOutcome: '', classificationFallback: true } }];
}

// Rule 2: response starts with "[opencode error]" → INCOMPLETE (provider error)
if (response.startsWith('[opencode error]')) {
  return [{ json: { outcome: 'INCOMPLETE', rawOutcome: response, classificationFallback: false } }];
}

// Rule 3: salvaged==yes OR rc!=0 → INCOMPLETE (timeout/crash)
if (salvaged === 'yes' || (Number.isFinite(rc) && rc !== 0)) {
  return [{ json: { outcome: 'INCOMPLETE', rawOutcome: response, classificationFallback: false } }];
}

// Rule 4-5: fall through to LLM
return [{ json: { outcome: null, response } }];

const item = $input.first().json;

// If the classifier sub-workflow or LLM node errored, treat as UNKNOWN
if (item.error !== undefined) {
  return { outcome: 'UNKNOWN', rawOutcome: String(item.error?.message ?? item.error), classificationFallback: true };
}

// Deterministic path: Determine outcome already classified
if (item.outcome !== undefined && item.outcome !== null) {
  return { outcome: item.outcome, rawOutcome: item.rawOutcome, classificationFallback: item.classificationFallback || false };
}

// LLM path: validate the agent's output
const outcomes = ['COMPLETE', 'QUESTION', 'INCOMPLETE'];
const raw = item.output;
const agentOutcome = (raw || '')
  .trim()
  .replace(/^[\'\"\u201c\u201d]+|[\'\"\u201c\u201d.!?;]+$/g, '')
  .trim()
  .toUpperCase();

if (!outcomes.includes(agentOutcome)) {
  return { outcome: 'UNKNOWN', rawOutcome: raw, classificationFallback: true };
}

return { outcome: agentOutcome };
